     1	/// Utility class for safe type conversions and validation.
     2	class TypeUtils {
     3	  TypeUtils._();
     4	
     5	  /// Safely converts a dynamic value to String.
     6	  static String safeString(dynamic value, {String defaultValue = ''}) {
     7	    if (value == null) return defaultValue;
     8	    return value.toString();
     9	  }
    10	
    11	  /// Safely converts a dynamic value to int.
    12	  static int safeInt(dynamic value, {int defaultValue = 0}) {
    13	    if (value == null) return defaultValue;
    14	    if (value is int) return value;
    15	    if (value is num) return value.toInt();
    16	    return int.tryParse(value.toString()) ?? defaultValue;
    17	  }
    18	
    19	  /// Safely converts a dynamic value to double.
    20	  static double? safeDouble(dynamic value) {
    21	    if (value == null) return null;
    22	    if (value is num) return value.toDouble();
    23	    return double.tryParse(value.toString());
    24	  }
    25	
    26	  /// Safely converts a dynamic value to bool.
    27	  static bool safeBool(dynamic value, {bool defaultValue = false}) {
    28	    if (value is bool) return value;
    29	    return defaultValue;
    30	  }
    31	
    32	  /// Safely converts a dynamic value to `List<Map<String, dynamic>>`.
    33	  static List<Map<String, dynamic>> safeMapList(dynamic value) {
    34	    if (value == null) return [];
    35	    if (value is! List) return [];
    36	
    37	    return value
    38	        .whereType<Map>()
    39	        .map((entry) => Map<String, dynamic>.from(entry))
    40	        .toList();
    41	  }
    42	
    43	  /// Safely trims a string and returns empty string if null.
    44	  static String safeTrim(String? value) {
    45	    return value?.trim() ?? '';
    46	  }
    47	}

