     9	import 'package:flutter/material.dart';
    10	
    11	abstract final class AuthGateKeys {
    12	  static const loadingScreenKey = ValueKey('auth_gate_loading_screen');
    13	  static const authScreenKey = ValueKey('auth_gate_auth_screen');
    14	  static const startupSyncScreenKey = ValueKey('auth_gate_startup_sync_screen');
    15	  static const clickerScreenKey = ValueKey('auth_gate_clicker_screen');
    16	}
    17	
    18	class AuthGate extends StatefulWidget {
    19	  const AuthGate({super.key});
    20	
    21	  @override
    22	  State<AuthGate> createState() => _AuthGateState();
    23	}
    24	
    25	class _AuthGateState extends State<AuthGate> {
    26	  Future<AthleteProfile>? _profileFuture;
    27	  String? _lastUid;
    28	  bool _roleSaved = false;
    29	
    30	  Future<AthleteProfile> _loadProfile() =>
    31	      PrefsRepository.create().then((r) => r.loadAthleteProfile());
    32	
    33	  @override
    34	  Widget build(BuildContext context) {
    35	    return StreamBuilder<User?>(
    36	      stream: FirebaseAuth.instance.authStateChanges(),
    37	      builder: (context, snapshot) {
    38	        if (snapshot.connectionState == ConnectionState.waiting) {
    39	          return const Scaffold(
    40	            key: AuthGateKeys.loadingScreenKey,
    41	            body: Center(child: CircularProgressIndicator()),
    42	          );
    43	        }
    44	
    45	        if (snapshot.data == null) {
    46	          _profileFuture = null;
    47	          _lastUid = null;
    48	          _roleSaved = false;
    49	          return const AuthScreen(key: AuthGateKeys.authScreenKey);
    50	        }
    51	
    52	        final uid = snapshot.data!.uid;
    53	        if (_profileFuture == null || _lastUid != uid) {
    54	          _profileFuture = _loadProfile();
    55	          _lastUid = uid;
    56	          _roleSaved = false;
    57	        }
    58	
    59	        return FutureBuilder<AthleteProfile>(
    60	          future: _profileFuture,
    61	          builder: (context, roleSnapshot) {
    62	            if (!roleSnapshot.hasData) {
    63	              return const Scaffold(
    64	                key: AuthGateKeys.loadingScreenKey,
    65	                body: Center(child: CircularProgressIndicator()),
    66	              );
    67	            }
    68	            final profile = roleSnapshot.data!;
    69	            if (profile.role.isEmpty && !_roleSaved) {
    70	              return RoleSetupScreen(
    71	                key: AuthGateKeys.authScreenKey,
    72	                onSaved: () => setState(() {
    73	                  _roleSaved = true;
    74	                  _profileFuture = _loadProfile();
    75	                }),
    76	              );
    77	            }
    78	            return const StartupSyncedClickerScreen(
    79	              key: AuthGateKeys.startupSyncScreenKey,
    80	            );
    81	          },
    82	        );
    83	      },
    84	    );
    85	  }
    86	}
    87	
    88	class RoleSetupScreen extends StatefulWidget {
    89	  const RoleSetupScreen({super.key, this.onSaved});
    90	
    91	  final VoidCallback? onSaved;
    92	
    93	  @override
    94	  State<RoleSetupScreen> createState() => _RoleSetupScreenState();
    95	}
    96	
    97	class _RoleSetupScreenState extends State<RoleSetupScreen> {
    98	  String? _role;
    99	  bool _saving = false;
   100	
   101	  Future<void> _saveRole() async {
   102	    if (_role == null) return;
   103	    setState(() => _saving = true);
   104	    final repo = await PrefsRepository.create();
   105	    // Preserve existing profile fields; only mutate role.
   106	    final existing = repo.loadAthleteProfile();
   107	    await repo.saveAthleteProfile(existing.copyWith(role: _role!));
   108	    if (!mounted) return;
   109	    setState(() => _saving = false);
   110	    widget.onSaved?.call();
   111	  }
   112	
   113	  @override
   114	  Widget build(BuildContext context) {
   115	    final l10n = AppLocalizations.of(context);
   116	    return Scaffold(
   117	      body: Center(
   118	        child: Padding(
   119	          padding: const EdgeInsets.all(24),
   120	          child: ConstrainedBox(
   121	            constraints: const BoxConstraints(maxWidth: 420),
   122	            child: Column(
   123	              mainAxisSize: MainAxisSize.min,
   124	              crossAxisAlignment: CrossAxisAlignment.stretch,
   125	              children: [
   126	                Text(l10n.roleRequired, textAlign: TextAlign.center),
   127	                const SizedBox(height: 16),
   128	                DropdownButtonFormField<String>(
   129	                  initialValue: _role,
   130	                  hint: Text(l10n.roleLabel),

